import{_ as t,o,c as i,a2 as a}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"AI Models","description":"","frontmatter":{},"headers":[],"relativePath":"features/models.md","filePath":"features/models.md"}'),r={name:"features/models.md"};function n(l,e,s,d,p,h){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="ai-models" tabindex="-1">AI Models <a class="header-anchor" href="#ai-models" aria-label="Permalink to &quot;AI Models&quot;">​</a></h1><p>Lyra Code supports multiple AI model providers, giving you the flexibility to choose the best model for your task.</p><h2 id="supported-providers" tabindex="-1">Supported Providers <a class="header-anchor" href="#supported-providers" aria-label="Permalink to &quot;Supported Providers&quot;">​</a></h2><h3 id="openai-chat-completions" tabindex="-1">OpenAI Chat Completions <a class="header-anchor" href="#openai-chat-completions" aria-label="Permalink to &quot;OpenAI Chat Completions&quot;">​</a></h3><p>Connect to any OpenAI Chat Completions-compatible API. This includes:</p><ul><li><strong>OpenAI</strong> — GPT-4o, GPT-4, o1, o3 series</li><li><strong>Third-party providers</strong> with compatible APIs (OpenRouter, Groq, Together AI, etc.)</li><li><strong>Self-hosted</strong> solutions like Ollama, vLLM, LocalAI</li></ul><h3 id="anthropic-messages-api" tabindex="-1">Anthropic Messages API <a class="header-anchor" href="#anthropic-messages-api" aria-label="Permalink to &quot;Anthropic Messages API&quot;">​</a></h3><p>Full support for Anthropic&#39;s Messages API:</p><ul><li>Claude Opus, Sonnet, Haiku series</li><li>Streaming and non-streaming modes</li><li>Extended thinking / reasoning depth control</li></ul><h3 id="gemini-generatecontent-api" tabindex="-1">Gemini GenerateContent API <a class="header-anchor" href="#gemini-generatecontent-api" aria-label="Permalink to &quot;Gemini GenerateContent API&quot;">​</a></h3><p>Google&#39;s Gemini models are natively supported:</p><ul><li>Gemini 2.5 Pro, 2.5 Flash</li><li>Gemini 2.0 Flash, 1.5 Pro</li><li>Multimodal input (text + images)</li></ul><h2 id="provider-configuration" tabindex="-1">Provider Configuration <a class="header-anchor" href="#provider-configuration" aria-label="Permalink to &quot;Provider Configuration&quot;">​</a></h2><p>Each provider can be configured with:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>API Key</td><td>Your authentication key</td></tr><tr><td>Base URL</td><td>API endpoint (customizable)</td></tr><tr><td>Model</td><td>Model name / identifier</td></tr><tr><td>Extra Headers</td><td>Custom HTTP headers</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">HTTP API Warning</p><p>HTTP (non-HTTPS) API URLs are supported but trigger an <strong>explicit security warning</strong>. Always prefer HTTPS in production.</p></div><h2 id="fast-model-switching" tabindex="-1">Fast Model Switching <a class="header-anchor" href="#fast-model-switching" aria-label="Permalink to &quot;Fast Model Switching&quot;">​</a></h2><p>Lyra Code allows you to change models <strong>mid-conversation</strong> without losing context:</p><ul><li>Switch between different providers and models instantly</li><li>Change system prompts on the fly</li><li>Adjust reasoning depth for supported models</li></ul><h2 id="model-profiles" tabindex="-1">Model Profiles <a class="header-anchor" href="#model-profiles" aria-label="Permalink to &quot;Model Profiles&quot;">​</a></h2><p>Save multiple provider configurations as profiles. Each profile can have its own:</p><ul><li>API key and endpoint</li><li>Default model</li><li>Preferred system prompt</li><li>Reasoning parameters</li></ul><p>Quickly switch between profiles depending on your task — coding, creative writing, research, or automation.</p>',23)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
